<?php require_once __DIR__.'/../../backend/shared/auth.php'; require_role('doctor'); require_once __DIR__.'/../../backend/shared/ai_engine.php'; require_once __DIR__.'/../../backend/shared/layout.php';
$hn=$_GET['hn']??$_POST['hn']??''; $p=null; if($hn){$st=db()->prepare('SELECT * FROM patients WHERE hn=?');$st->execute([$hn]);$p=$st->fetch();}
if($_SERVER['REQUEST_METHOD']==='POST' && $p){$r=assess_ventilator($_POST);$st=db()->prepare('INSERT INTO ventilator_cases(patient_id,recorded_at,ventilator_id,mode_name,pip,peep,vte,flow,pressure_avg,rr,ai_score,ai_level,ai_note) VALUES(?,NOW(),?,?,?,?,?,?,?,?,?,?)');$st->execute([$p['id'],$_POST['ventilator_id'],$_POST['mode_name'],$_POST['pip'],$_POST['peep'],$_POST['vte'],$_POST['flow'],$_POST['pressure_avg'],$_POST['rr'],$r['score'],$r['level'],implode(', ',$r['reasons']).' / '.$r['recommendation']]); $saved=true;}
$cases=db()->query('SELECT vc.*,p.hn,p.first_name,p.last_name FROM ventilator_cases vc JOIN patients p ON p.id=vc.patient_id ORDER BY vc.id DESC LIMIT 30')->fetchAll();
app_header('ICU Ventilator AI','doctor','icu'); ?><a class="back" href="dashboard.php">← กลับ Dashboard</a><div class="grid two"><div class="card"><h3>บันทึกข้อมูลเครื่องช่วยหายใจ</h3><?php if(!empty($saved)):?><div class="notice">บันทึก ICU case และประเมิน AI แล้ว</div><?php endif;?><form method="post" class="form-stack"><div class="field"><label>HN</label><input name="hn" value="<?=e($hn)?>" placeholder="HN000010" required></div><div class="row"><div class="field"><label>Ventilator ID</label><input name="ventilator_id"></div><div class="field"><label>Mode</label><select name="mode_name"><option>VCV</option><option>PCV</option><option>SIMV</option><option>PSV</option></select></div><div class="field"><label>PIP</label><input name="pip" type="number" step="0.1"></div><div class="field"><label>PEEP</label><input name="peep" type="number" step="0.1"></div><div class="field"><label>Vte</label><input name="vte" type="number" step="0.1"></div><div class="field"><label>Flow</label><input name="flow" type="number" step="0.1"></div><div class="field"><label>Pressure Avg</label><input name="pressure_avg" type="number" step="0.1"></div><div class="field"><label>RR</label><input name="rr" type="number"></div></div><button class="btn">บันทึก + AI วิเคราะห์ ICU</button></form></div><div class="card"><h3>แนวข้อมูล ICU</h3><p class="tl-meta">รองรับ field จาก waveform: Flow, Pressure, Volume และ metadata เช่น ventilator/patient/diagnosis</p><div class="riskbox">AI จะให้คะแนนจาก PIP, PEEP, Vte, Flow, RR เพื่อคัดกรองความผิดปกติของเครื่องช่วยหายใจเบื้องต้น</div></div></div><div class="card" style="margin-top:18px"><h3>ICU Cases ล่าสุด</h3><table class="table"><tr><th>HN</th><th>Mode</th><th>PIP/PEEP</th><th>Vte</th><th>AI</th><th>Note</th></tr><?php foreach($cases as $c):?><tr><td><?=e($c['hn'])?></td><td><?=e($c['mode_name'])?></td><td><?=e($c['pip'])?>/<?=e($c['peep'])?></td><td><?=e($c['vte'])?></td><td><span class="badge <?=$c['ai_level']==='High'?'red':($c['ai_level']==='Moderate'?'warn':'')?>"><?=e($c['ai_level'])?> <?=$c['ai_score']?></span></td><td><?=e($c['ai_note'])?></td></tr><?php endforeach;?></table></div><?php app_footer();?>
